+from __future__ import annotations
+
+import json
+import re
+from datetime import datetime
+from pathlib import Path
+from typing import Any
+
+import numpy as np
+import pandas as pd
+
+PROJECT_ROOT = Path(__file__).resolve().parents[1]
+REPORT_DIR = PROJECT_ROOT / "research" / "reports"
+
+
+def extract_date_tag(path: Path) -> str:
+    match = re.search(r"(\d{8})", path.name)
+    return match.group(1) if match else ""
+
+
+def latest_file(pattern: str) -> Path | None:
+    files = list(REPORT_DIR.glob(pattern))
+    if not files:
+        return None
+    return sorted(files, key=lambda p: (extract_date_tag(p), p.stat().st_mtime), reverse=True)[0]
+
+
+def load_json(path: Path | None) -> dict[str, Any]:
+    if path is None or not path.exists():
+        return {}
+    return json.loads(path.read_text(encoding="utf-8"))
+
+
+def load_csv(path: Path | None) -> pd.DataFrame:
+    if path is None or not path.exists():
+        return pd.DataFrame()
+    return pd.read_csv(path)
+
+
+def build_feasible_rank(df: pd.DataFrame, sort_mode: str) -> pd.DataFrame:
+    if df.empty:
+        return df.copy()
+    req_cols = {"annual_return_pct", "max_drawdown_pct", "sharpe"}
+    if not req_cols.issubset(df.columns):
+        return pd.DataFrame()
+
+    feasible = df[(df["annual_return_pct"] >= 40.0) & (df["max_drawdown_pct"] <= 25.0)].copy()
+    if feasible.empty:
+        return feasible
+
+    if sort_mode == "annual":
+        feasible = feasible.sort_values(
+            ["annual_return_pct", "sharpe", "max_drawdown_pct"],
+            ascending=[False, False, True],
+        )
+    else:
+        feasible = feasible.sort_values(
+            ["max_drawdown_pct", "annual_return_pct", "sharpe"],
+            ascending=[True, False, False],
+        )
+
+    feasible = feasible.reset_index(drop=True)
+    feasible.insert(0, "rank", np.arange(1, len(feasible) + 1))
+    return feasible
+
+
+def safe_float(value: Any) -> float:
+    try:
+        return float(value)
+    except Exception:
+        return np.nan
+
+
+def locate_selected_rank(df: pd.DataFrame, selected: dict[str, Any]) -> int | None:
+    if df.empty or not selected:
+        return None
+    cols = [
+        "topk",
+        "n_drop",
+        "hold_thresh",
+        "risk_degree",
+        "breadth_low_th",
+        "breadth_mid_th",
+        "breadth_low_scale",
+        "breadth_mid_scale",
+        "breadth_high_scale",
+    ]
+    mask = np.ones(len(df), dtype=bool)
+    for col in cols:
+        if col in df.columns and col in selected:
+            left = pd.to_numeric(df[col], errors="coerce")
+            right = safe_float(selected[col])
+            mask = mask & np.isclose(left, right, rtol=1e-8, atol=1e-8)
+
+    matched = df.loc[mask]
+    if matched.empty:
+        return None
+    rank_value = matched.iloc[0].get("rank")
+    if pd.isna(rank_value):
+        return None
+    return int(rank_value)
+
+
+def display_columns(df: pd.DataFrame) -> pd.DataFrame:
+    prefer = [
+        "rank",
+        "topk",
+        "n_drop",
+        "hold_thresh",
+        "risk_degree",
+        "breadth_low_th",
+        "breadth_mid_th",
+        "breadth_low_scale",
+        "breadth_mid_scale",
+        "breadth_high_scale",
+        "annual_return_pct",
+        "max_drawdown_pct",
+        "sharpe",
+        "excess_annual_return_pct",
+        "excess_max_drawdown_pct",
+        "wf_min_annual_pct",
+        "wf_max_mdd_pct",
+        "wf_min_sharpe",
+        "turnover_ratio",
+        "avg_scale",
+        "min_scale",
+        "objective",
+        "robust_pass",
+    ]
+    cols = [c for c in prefer if c in df.columns]
+    return df[cols].copy() if cols else df.copy()
+
+
+def to_records(df: pd.DataFrame) -> list[dict[str, Any]]:
+    if df.empty:
+        return []
+    out = df.copy()
+    for col in out.columns:
+        if pd.api.types.is_datetime64_any_dtype(out[col]):
+            out[col] = out[col].dt.strftime("%Y-%m-%d")
+        elif pd.api.types.is_float_dtype(out[col]):
+            out[col] = out[col].round(6)
+    return out.to_dict("records")
+
+
+def fmt(value: Any, digits: int = 2, suffix: str = "") -> str:
+    if value is None:
+        return "-"
+    if isinstance(value, str):
+        return value
+    try:
+        return f"{float(value):.{digits}f}{suffix}"
+    except Exception:
+        return "-"
+
+
+def main() -> None:
+    REPORT_DIR.mkdir(parents=True, exist_ok=True)
+    now_str = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
+
+    summary_file = latest_file("qlib_breadth_long_defensive_summary_*.json")
+    grid_file = latest_file("qlib_breadth_long_defensive_grid_*.csv")
+    annual_rank_file = latest_file("qlib_breadth_long_defensive_feasible_rank_by_annual_*.csv")
+    mdd_rank_file = latest_file("qlib_breadth_long_defensive_feasible_rank_by_mdd_*.csv")
+    long_curve_file = latest_file("qlib_long_curve_*.csv")
+    live_system_file = latest_file("live_system_v1_*.json")
+    combo_curve_file = latest_file("live_system_v1_combo_curve_*.csv")
+
+    summary = load_json(summary_file)
+    selected = summary.get("selected", {}) if isinstance(summary, dict) else {}
+
+    grid_df = load_csv(grid_file)
+    annual_rank_df = load_csv(annual_rank_file)
+    mdd_rank_df = load_csv(mdd_rank_file)
+
+    if annual_rank_df.empty and not grid_df.empty:
+        annual_rank_df = build_feasible_rank(grid_df, sort_mode="annual")
+    if mdd_rank_df.empty and not grid_df.empty:
+        mdd_rank_df = build_feasible_rank(grid_df, sort_mode="mdd")
+
+    if not grid_df.empty and {"annual_return_pct", "max_drawdown_pct"}.issubset(grid_df.columns):
+        grid_df = grid_df.copy()
+        grid_df["is_feasible"] = (grid_df["annual_return_pct"] >= 40.0) & (grid_df["max_drawdown_pct"] <= 25.0)
+    else:
+        grid_df["is_feasible"] = False
+
+    long_curve_df = load_csv(long_curve_file)
+    if not long_curve_df.empty and "date" in long_curve_df.columns:
+        long_curve_df["date"] = pd.to_datetime(long_curve_df["date"], errors="coerce")
+        long_curve_df = long_curve_df.dropna(subset=["date"]).sort_values("date")
+
+    combo_curve_df = load_csv(combo_curve_file)
+    if not combo_curve_df.empty and "date" in combo_curve_df.columns:
+        combo_curve_df["date"] = pd.to_datetime(combo_curve_df["date"], errors="coerce")
+        combo_curve_df = combo_curve_df.dropna(subset=["date"]).sort_values("date")
+
+    live_system = load_json(live_system_file)
+    combo_v1 = live_system.get("combo_v1", {}) if isinstance(live_system, dict) else {}
+    period = summary.get("period", {}) if isinstance(summary, dict) else {}
+
+    selected_rank_annual = locate_selected_rank(annual_rank_df, selected)
+    selected_rank_mdd = locate_selected_rank(mdd_rank_df, selected)
+
+    annual_table_html = (
+        display_columns(annual_rank_df).to_html(index=False, classes="data-table", border=0) if not annual_rank_df.empty else "<p>无数据</p>"
+    )
+    mdd_table_html = (
+        display_columns(mdd_rank_df).to_html(index=False, classes="data-table", border=0) if not mdd_rank_df.empty else "<p>无数据</p>"
+    )
+
+    long_curve_records = to_records(long_curve_df)
+    combo_curve_records = to_records(combo_curve_df)
+    scatter_records = to_records(grid_df)
+    annual_rank_records = to_records(annual_rank_df)
+
+    selected_params = (
+        f"topk={selected.get('topk', '-')}, "
+        f"n_drop={selected.get('n_drop', '-')}, "
+        f"hold={selected.get('hold_thresh', '-')}, "
+        f"risk={selected.get('risk_degree', '-')}, "
+        f"th={selected.get('breadth_low_th', '-')}/{selected.get('breadth_mid_th', '-')}, "
+        f"scale={selected.get('breadth_low_scale', '-')}/{selected.get('breadth_mid_scale', '-')}/{selected.get('breadth_high_scale', '-')}"
+    )
+
+    source_info = {
+        "summary_file": str(summary_file) if summary_file else "-",
+        "grid_file": str(grid_file) if grid_file else "-",
+        "annual_rank_file": str(annual_rank_file) if annual_rank_file else "-",
+        "mdd_rank_file": str(mdd_rank_file) if mdd_rank_file else "-",
+        "long_curve_file": str(long_curve_file) if long_curve_file else "-",
+        "live_system_file": str(live_system_file) if live_system_file else "-",
+        "combo_curve_file": str(combo_curve_file) if combo_curve_file else "-",
